# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Threading.Tasks;

[ApiController]
[Route("api/[controller]")]
public class FileController : ControllerBase
{
    private readonly string _baseDirectory = Path.Combine(Directory.GetCurrentDirectory(), "uploads");

    [HttpGet("{filename}")]
    public async Task<IActionResult> GetFile(string filename)
    {
        if (string.IsNullOrEmpty(filename))
            return BadRequest("Filename is required.");

        var sanitizedFilename = Path.GetFileName(filename);
        var resolvedPath = Path.GetFullPath(Path.Combine(_baseDirectory, sanitizedFilename));

        if (!resolvedPath.StartsWith(_baseDirectory, StringComparison.OrdinalIgnoreCase))
            return BadRequest("Invalid file path.");

        if (!System.IO.File.Exists(resolvedPath))
            return NotFound("File not found.");

        var fileExtension = Path.GetExtension(resolvedPath).ToLowerInvariant();
        var contentType = GetContentType(fileExtension);

        var fileBytes = await System.IO.File.ReadAllBytesAsync(resolvedPath);
        return File(fileBytes, contentType, sanitizedFilename);
    }

    private string GetContentType(string extension)
    {
        return extension switch
        {
            ".pdf" => "application/pdf",
            ".jpg" or ".jpeg" => "image/jpeg",
            ".png" => "image/png",
            ".gif" => "image/gif",
            ".bmp" => "image/bmp",
            ".tiff" or ".tif" => "image/tiff",
            ".txt" => "text/plain",
            ".html" or ".htm" => "text/html",
            ".css" => "text/css",
            ".js" => "application/javascript",
            ".json" => "application/json",
            ".xml" => "application/xml",
            ".doc" => "application/msword",
            ".docx" => "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
            ".xls" => "application/vnd.ms-excel",
            ".xlsx" => "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            ".ppt" => "application/vnd.ms-powerpoint",
            ".pptx" => "application/vnd.openxmlformats-officedocument.presentationml.presentation",
            ".zip" => "application/zip",
            ".rar" => "application/vnd.rar",
            ".7z" => "application/x-7z-compressed",
            ".mp3" => "audio/mpeg",
            ".wav" => "audio/wav",
            ".mp4" => "video/mp4",
            ".avi" => "video/x-msvideo",
            _ => "application/octet-stream"
        };
    }
}